// Tier mapping — must stay in sync with lib/pricing.ts
// Keys are setup fee amounts in DOLLARS
const TIER_BY_AMOUNT = {
  39:  { slug: 'presence',       name: 'Presence',         monthlyAmount: 99,  monthlyLink: 'https://checkout.square.site/merchant/MLTDBEPZS805X/checkout/V3YMPG3KCU2WBR6TVKHRG3ZZ' },
  59:  { slug: 'growth',         name: 'Growth',           monthlyAmount: 149, monthlyLink: 'https://checkout.square.site/merchant/MLTDBEPZS805X/checkout/AAU7Z73OQAID3NKACN3NRREY' },
  199: { slug: 'ai-first',       name: 'AI-First',         monthlyAmount: 349, monthlyLink: 'https://checkout.square.site/merchant/MLTDBEPZS805X/checkout/OU4GK2ZLA55RKCKBSSHQYJUY' },
};

// $99 setups — disambiguate by payment link ID embedded in order metadata
// These IDs are the setupLinkId values from lib/pricing.ts
const TIER_BY_LINK_ID = {
  'R5TCDCXYIUABP3TA': { slug: 'revenue-engine',        name: 'Revenue Engine',        monthlyAmount: 249, monthlyLink: 'https://checkout.square.site/merchant/MLTDBEPZS805X/checkout/DJDCDH57E74WKIXDU62MKAZE' },
  '4VUKHAXKQEC2EAFO': { slug: 'ai-automation-starter', name: 'AI Automation Starter', monthlyAmount: 99,  monthlyLink: 'https://checkout.square.site/merchant/MLTDBEPZS805X/checkout/JLUTDJWBJVGMSRT3UIUXPQKD' },
  'KHQJJWZ4JZMDT7JW': { slug: 'consulting',            name: 'Consulting',            monthlyAmount: 99,  monthlyLink: 'https://checkout.square.site/merchant/MLTDBEPZS805X/checkout/2A27LH5ZQGWEDG5YPZF27DHH' },
};

// Known monthly amounts — flag these as monthly (not setup)
const MONTHLY_AMOUNTS = new Set([99, 149, 249, 349]);

const item = $input.first().json;

// Deduplication: skip if this payment_id was already processed
// Handles Square sending both payment.created and payment.updated for same payment
const seen = $getWorkflowStaticData('global');
if (!seen.processedPaymentIds) seen.processedPaymentIds = [];
const paymentId = item.payment_id;
if (paymentId && seen.processedPaymentIds.includes(paymentId)) {
  return [{ json: { ...item, tier_matched: false, is_monthly: false, skipped_duplicate: true, unmatched_reason: 'Duplicate payment_id: ' + paymentId } }];
}
if (paymentId) seen.processedPaymentIds.push(paymentId);
// Keep last 500 IDs to avoid unbounded growth
if (seen.processedPaymentIds.length > 500) seen.processedPaymentIds = seen.processedPaymentIds.slice(-500);

const amountDollars = item.amount_dollars;
const orderId = item.order_id ?? '';

let result = { ...item, tier_matched: false, is_monthly: false };

// Check if this looks like a monthly recurring charge
// (In practice, Square recurring invoices come via invoice.payment_made not payment.created,
//  but guard here just in case)
if (amountDollars === 99 || amountDollars === 149 || amountDollars === 249 || amountDollars === 349) {
  // Could be monthly OR a $99 setup — try to match setup first
}

// Try unambiguous amount match first
if (TIER_BY_AMOUNT[amountDollars]) {
  const tier = TIER_BY_AMOUNT[amountDollars];
  result = { ...result, ...tier, tier_matched: true, setup_amount: amountDollars };
} else if (amountDollars === 99) {
  // Ambiguous — try to match by payment link ID in the order ID
  // Square embeds the payment link ID in order metadata; we stored it as setupLinkId
  // Try matching order_id substring against known link IDs
  const matchedLinkId = Object.keys(TIER_BY_LINK_ID).find(id => orderId.includes(id));
  if (matchedLinkId) {
    const tier = TIER_BY_LINK_ID[matchedLinkId];
    result = { ...result, ...tier, tier_matched: true, setup_amount: 99 };
  } else {
    // $99 but can't determine which tier — flag for manual review
    result.unmatched_payment = true;
    result.unmatched_reason = '$99 payment could not be matched to a tier via order_id';
  }
} else if (MONTHLY_AMOUNTS.has(amountDollars)) {
  result.is_monthly = true;
  result.unmatched_reason = `Monthly payment of $${amountDollars} received — no action needed (subscription active)`;
} else {
  result.unmatched_payment = true;
  result.unmatched_reason = `Unknown amount: $${amountDollars}`;
}

return [{ json: result }];

